ADMIN_HTML = '<!DOCTYPE html>\n<html lang="ja">\n<head>\n    <meta charset="UTF-8">\n    <meta name="viewport" content="width=device-width, initial-scale=1.0">\n    <title>配車手配システム - 4ステップ完全統合プレビュー</title>\n    <script src="https://cdn.tailwindcss.com"></script>\n    <style>\n        .line-green {\n            background-color: #06C755;\n        }\n\n        .line-bg {\n            background-color: #849ebf;\n        }\n\n        .chat-bubble {\n            position: relative;\n        }\n\n        .chat-bubble.left::before {\n            content: "";\n            position: absolute;\n            top: 10px;\n            left: -8px;\n            border: 8px solid transparent;\n            border-right-color: white;\n            border-left: 0;\n            border-top: 0;\n            margin-top: -4px;\n        }\n\n        .chat-bubble.right::before {\n            content: "";\n            position: absolute;\n            top: 10px;\n            right: -8px;\n            border: 8px solid transparent;\n            border-left-color: #06C755;\n            border-right: 0;\n            border-top: 0;\n            margin-top: -4px;\n        }\n\n        ::-webkit-scrollbar {\n            width: 6px;\n        }\n\n        ::-webkit-scrollbar-track {\n            background: transparent;\n        }\n\n        ::-webkit-scrollbar-thumb {\n            background: rgba(0, 0, 0, 0.2);\n            border-radius: 10px;\n        }\n\n        .liff-modal {\n            transform: translateY(100%);\n            transition: transform 0.4s cubic-bezier(0.16, 1, 0.3, 1);\n        }\n\n        .liff-modal.open {\n            transform: translateY(0);\n        }\n\n        .new-request-anim {\n            animation: highlight 2s ease-out;\n        }\n\n        @keyframes highlight {\n            0% {\n                background-color: #fef08a;\n            }\n\n            100% {\n                background-color: white;\n            }\n        }\n\n        .fade-screen {\n            transition: opacity 0.4s ease-in-out;\n        }\n\n        .screen-hidden {\n            display: none !important;\n        }\n\n        .accordion-content {\n            transition: max-height 0.3s ease-in-out, opacity 0.3s ease-in-out, padding 0.3s ease-in-out;\n            max-height: 0;\n            opacity: 0;\n            overflow: hidden;\n        }\n\n        .accordion-content.open {\n            max-height: 500px;\n            opacity: 1;\n            padding-top: 1rem;\n            padding-bottom: 1rem;\n        }\n\n        .partner-card.active {\n            border-color: #3b82f6;\n            box-shadow: 0 4px 6px -1px rgba(59, 130, 246, 0.1), 0 2px 4px -1px rgba(59, 130, 246, 0.06);\n        }\n\n        /* Step Indicator */\n        .step-active {\n            background-color: #3b82f6;\n            color: white;\n            border-color: #3b82f6;\n        }\n\n        .step-inactive {\n            background-color: white;\n            color: #9ca3af;\n            border-color: #e5e7eb;\n        }\n\n        .step-done {\n            background-color: #10b981;\n            color: white;\n            border-color: #10b981;\n        }\n    </style>\n</head>\n<body class="bg-slate-50 min-h-screen flex items-center justify-center font-sans text-gray-800 p-0 md:p-4">\n    <div class="w-full h-[100dvh] md:h-[700px] md:w-[450px] bg-white md:rounded-2xl shadow-2xl overflow-hidden flex flex-col relative border border-gray-200">\n        <!-- グローバルヘッダー (バナー) -->\n                    <div\n                        class="bg-gray-900 text-white p-2 px-4 shadow-md flex justify-between items-center z-20 shrink-0 relative">\n                        <span class="font-bold text-xs tracking-wide">HubCargo 管理システム</span>\n                        <button onclick="openSettings()" class="hover:bg-gray-700 p-1.5 rounded transition group"\n                            title="設定">\n                            <svg class="w-4 h-4 text-gray-300 group-hover:text-white transition-colors" fill="none"\n                                stroke="currentColor" viewBox="0 0 24 24">\n                                <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2"\n                                    d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z">\n                                </path>\n                                <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2"\n                                    d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path>\n                            </svg>\n                        </button>\n                    </div>\n\n                    <!-- 【画面A】受信トレイ（顧客からの連絡） -->\n                    <div id="screen-inbox"\n                        class="fade-screen flex flex-col flex-1 w-full bg-gray-50 h-full overflow-hidden">\n                        <div class="bg-indigo-900 text-white p-3 shadow-md">\n                            <h2 class="font-bold text-sm">📥 顧客からのお問い合わせ</h2>\n                        </div>\n                        <div class="flex-1 p-3 overflow-y-auto pb-20">\n                            <div id="inboxList" class="space-y-3">\n                                <div class="text-center py-10 text-gray-400 text-sm" id="emptyInbox">顧客からのお問い合わせを待機中...\n                                </div>\n                            </div>\n                        </div>\n                    </div>\n\n                    <!-- 【画面B】手配・協力会社の連絡 -->\n                    <div id="screen-dispatch"\n                        class="fade-screen screen-hidden flex flex-col flex-1 w-full bg-gray-50 h-full overflow-hidden">\n                        <div class="bg-slate-800 text-white p-3 shadow-md flex items-center justify-between">\n                            <h2 class="font-bold text-sm">🚚 協力会社の手配・進行状況</h2>\n                        </div>\n\n                        <div id="dispatch-content" class="flex-1 flex flex-col overflow-hidden hidden">\n                            <div class="bg-blue-50 border-b border-blue-100 p-3 shrink-0">\n                                <h3 class="font-bold text-blue-800 text-xs mb-1">■ 手配中の案件データ</h3>\n                                <div\n                                    class="bg-white rounded p-2 text-[11px] grid grid-cols-2 gap-2 border border-blue-50">\n                                    <div>\n                                        <p class="text-[9px] text-gray-400">顧客名</p>\n                                        <p class="font-bold" id="pass-name">-</p>\n                                    </div>\n                                    <div>\n                                        <p class="text-[9px] text-gray-400">電話番号</p>\n                                        <p class="font-bold" id="pass-phone">-</p>\n                                    </div>\n                                    <div class="col-span-2">\n                                        <p class="text-[9px] text-gray-400">お問い合わせ内容</p>\n                                        <p class="text-gray-700" id="pass-detail">-</p>\n                                    </div>\n                                </div>\n                            </div>\n                            <div class="flex-1 p-3 overflow-y-auto pb-20">\n                                <p class="text-[11px] text-gray-500 mb-2 font-bold">送出先の協力会社を選択</p>\n\n                                <div class="bg-white border border-gray-200 rounded-lg overflow-hidden partner-card"\n                                    id="card-partner">\n                                    <button onclick="togglePartner()"\n                                        class="w-full px-3 py-3 flex justify-between items-center bg-gray-50">\n                                        <div class="flex items-center gap-2">\n                                            <div\n                                                class="w-8 h-8 bg-blue-100 text-blue-600 rounded-full flex items-center justify-center text-sm">\n                                                🏙️</div>\n                                            <div class="text-left">\n                                                <h4 class="font-bold text-sm">ファーストリンク</h4>\n                                                <p class="text-[9px] text-gray-500">関東エリア</p>\n                                            </div>\n                                        </div>\n                                        <svg class="w-4 h-4 text-gray-400 transition-transform" id="arrow-partner"\n                                            fill="none" stroke="currentColor" viewBox="0 0 24 24">\n                                            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2"\n                                                d="M19 9l-7 7-7-7"></path>\n                                        </svg>\n                                    </button>\n                                    <div id="form-partner" class="accordion-content bg-white px-3 border-t">\n                                        <p class="text-[10px] text-gray-500 mb-2 text-center bg-gray-50 p-1 rounded">\n                                            ※上の顧客データがLINEに送信されます</p>\n                                        <button onclick="sendToPartner()" id="btn-send-partner"\n                                            class="w-full bg-blue-600 text-white font-bold py-2 rounded shadow text-xs">\n                                            この会社へLINE送信\n                                        </button>\n                                    </div>\n                                </div>\n                            </div>\n                            <!-- ステータスバー -->\n                            <div class="bg-white p-2 border-t text-[11px] text-gray-600 shadow-[0_-2px_10px_rgba(0,0,0,0.05)] z-10 pb-16 shrink-0"\n                                id="dashStatus">\n                                <div class="flex items-center gap-2">\n                                    <span class="w-2 h-2 rounded-full bg-gray-300" id="statusDot"></span>\n                                    <span>ステータス: <span class="font-bold" id="statusText">待機中</span></span>\n                                </div>\n                            </div>\n                        </div>\n\n                        <div id="dispatch-empty" class="flex-1 flex items-center justify-center p-4 pb-20">\n                            <div class="text-center text-gray-400 text-sm">\n                                <svg class="w-10 h-10 mx-auto mb-2 text-gray-300" fill="none" stroke="currentColor"\n                                    viewBox="0 0 24 24">\n                                    <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2"\n                                        d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2">\n                                    </path>\n                                </svg>\n                                手配中の案件はありません。<br>「顧客からの連絡」タブから手配を進めてください。\n                            </div>\n                        </div>\n                    </div>\n                    \n                    <div id="screen-completed" class="fade-screen screen-hidden flex flex-col flex-1 w-full bg-gray-50 h-full overflow-hidden">\n                        <div class="bg-emerald-600 text-white p-3 shadow-md flex items-center justify-between z-10 shrink-0">\n                            <h2 class="font-bold text-sm">✅ 完了済みの案件</h2>\n                            <select id="archive-grouping" onchange="window.openGroups.clear(); renderCompletedGroups()" class="bg-emerald-700 text-white text-xs border border-emerald-500 rounded p-1 outline-none font-medium cursor-pointer focus:ring-1 focus:ring-emerald-400">\n                                <option value="month">月別</option>\n                                <option value="week">週別</option>\n                                <option value="year">年別</option>\n                            </select>\n                        </div>\n                        <div id="completedList" class="flex-1 p-3 overflow-y-auto pb-20"></div>\n                    </div>\n\n                    <!-- カスタムボトムタブナビゲーション -->\n                    <div\n                        class="absolute bottom-0 w-full bg-white border-t flex z-40 shadow-[0_-5px_15px_rgba(0,0,0,0.03)] h-14">\n                        <button onclick="switchTab(\'inbox\')" id="tab-inbox"\n                            class="flex-1 flex flex-col items-center justify-center gap-1 text-blue-600 bg-blue-50 border-t-2 border-blue-600 transition-colors">\n                            <svg class="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">\n                                <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2"\n                                    d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"></path>\n                            </svg>\n                            <span class="text-[10px] font-bold">顧客からの連絡</span>\n                            <!-- 未読バッジ -->\n                            <span id="inbox-badge"\n                                class="absolute top-1 left-[15%] bg-red-500 text-white text-[8px] font-bold px-1.5 py-0.5 rounded-full hidden">1</span>\n                        </button>\n                        <button onclick="switchTab(\'dispatch\')" id="tab-dispatch"\n                            class="flex-1 flex flex-col items-center justify-center gap-1 text-gray-400 border-t-2 border-transparent hover:bg-gray-50 transition-colors">\n                            <svg class="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">\n                                <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2"\n                                    d="M8 7h12m0 0l-4-4m4 4l-4 4m0 6H4m0 0l4 4m-4-4l4-4"></path>\n                            </svg>\n                            <span class="text-[10px] font-bold">協力会社の手配</span>\n                        </button>\n                        <button onclick="switchTab(\'completed\')" id="tab-completed"\n                            class="flex-1 flex flex-col items-center justify-center gap-1 text-gray-400 border-t-2 border-transparent hover:bg-gray-50 transition-colors">\n                            <svg class="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">\n                                <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2"\n                                    d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"></path>\n                            </svg>\n                            <span class="text-[10px] font-bold">完了済み</span>\n                        </button>\n                    </div>\n\n                    <!-- スライドアップする設定パネル -->\n                    <div id="settingsPanel"\n                        class="absolute inset-x-0 bottom-0 bg-white z-50 h-[90%] rounded-t-2xl shadow-[0_-10px_40px_rgba(0,0,0,0.3)] flex flex-col transform translate-y-full transition-transform duration-300 ease-out">\n                        <div class="flex justify-between items-center px-4 py-3 border-b bg-gray-50 rounded-t-2xl">\n                            <span class="font-bold text-sm text-gray-800 flex items-center gap-2"><svg\n                                    class="w-4 h-4 text-gray-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">\n                                    <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2"\n                                        d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z">\n                                    </path>\n                                    <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2"\n                                        d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path>\n                                </svg>管理設定</span>\n                            <button onclick="closeSettings()"\n                                class="text-gray-500 hover:bg-gray-200 p-1.5 rounded transition">✕</button>\n                        </div>\n                        <div class="flex-1 overflow-y-auto p-4 bg-gray-50">\n                            <!-- 協力会社リスト -->\n                            <div class="mb-5">\n                                <h3 class="font-bold text-[11px] text-gray-500 border-b pb-1 mb-3">協力会社・グループLINE管理</h3>\n                                <div id="partnerList" class="space-y-2">\n                                    <div class="text-center py-4 text-gray-400 text-xs">協力会社を取得中...</div>\n                                </div>\n\n                            <!-- 追加フォーム -->\n                            <div\n                                class="bg-white p-4 rounded-lg border border-indigo-100 shadow-sm mt-4 relative overflow-hidden">\n                                <div class="absolute top-0 left-0 w-1 h-full bg-indigo-500"></div>\n                                <h4 class="font-bold text-[11px] mb-3 text-indigo-800 flex items-center gap-1"><svg\n                                        class="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">\n                                        <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2"\n                                            d="M12 6v6m0 0v6m0-6h6m-6 0H6"></path>\n                                    </svg>新規会社・グループ追加</h4>\n                                <div class="space-y-2">\n                                    <div>\n                                        <label class="block text-[9px] text-gray-500 mb-0.5">会社名</label>\n                                        <input type="text" id="newPartnerName" placeholder="例: 株式会社サンプル"\n                                            class="w-full text-xs border border-gray-200 rounded p-2 focus:ring-1 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition">\n                                    </div>\n                                    <div>\n                                        <label class="block text-[9px] text-gray-500 mb-0.5">LINEグループ名 / ID</label>\n                                        <input type="text" id="newPartnerLine" placeholder="例: Grp_sample"\n                                            class="w-full text-xs border border-gray-200 rounded p-2 focus:ring-1 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition">\n                                    </div>\n                                    <button onclick="addPartner()"\n                                        class="w-full bg-indigo-600 hover:bg-indigo-700 text-white text-[11px] font-bold py-2 rounded shadow-sm transition-colors mt-2">\n                                        ＋ 追加する\n                                    </button>\n                                    <p id="addAlert" class="text-[9px] text-red-500 mt-1 hidden text-center">会社名は必須です\n                                    </p>\n                                </div>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n            </div>\n    </div>\n    \n<script>\n        const API_BASE = \'/api\';\n        \n        // --- 状態管理・UI更新 ---\n        let currentData = null; // Currently selected inquiry for dispatch\n        let allPartners = [];\n        let pollingInterval = null;\n        window.lastInquiries = []; // store for re-rendering archive\n        window.openGroups = new Set(); // store to keep accordion states open\n\n        // ==========================\n        // Auth & Auto Logout Logic\n        // ==========================\n        function checkAutoLogout() {\n            const LOGOUT_MS = 6 * 60 * 60 * 1000; // 6 hours\n            const loginTime = localStorage.getItem(\'hubcargo_login_time\');\n            const now = Date.now();\n\n            if (!loginTime) {\n                localStorage.setItem(\'hubcargo_login_time\', now.toString());\n            } else if (now - parseInt(loginTime) > LOGOUT_MS) {\n                alert("セキュリティ保護のため、自動的にログアウトしました。再度ログインしてください。");\n                localStorage.removeItem(\'hubcargo_login_time\');\n                // Basic認証のキャッシュを上書きしてログアウトさせる特殊URL\n                window.location.href = \'https://logout@\' + window.location.host + \'/admin.html\';\n            }\n        }\n\n        document.addEventListener(\'DOMContentLoaded\', () => {\n            checkAutoLogout();\n            fetchPartners();\n            fetchInquiries();\n            // Start basic polling for inbox (every 10s)\n            pollingInterval = setInterval(() => {\n                checkAutoLogout();\n                fetchInquiries();\n            }, 10000);\n        });\n\n        // ==========================\n        // Data Fetching\n        // ==========================\n        \n        // Settings Modal\n        function openSettings() {\n            document.getElementById(\'settingsModal\').classList.remove(\'hidden\');\n            document.getElementById(\'settingsModal\').classList.add(\'flex\');\n        }\n\n        function closeSettings() {\n            document.getElementById(\'settingsModal\').classList.add(\'hidden\');\n            document.getElementById(\'settingsModal\').classList.remove(\'flex\');\n        }\n\n        async function addNewPartner() {\n            const name = document.getElementById(\'newPartnerName\').value;\n            const lineId = document.getElementById(\'newPartnerLineId\').value;\n            \n            if (!name) {\n                alert("会社名を入力してください");\n                return;\n            }\n\n            try {\n                const response = await fetch(\'/api/partners\', {\n                    method: \'POST\',\n                    headers: { \'Content-Type\': \'application/json\' },\n                    body: JSON.stringify({ name: name, line_group_id: lineId })\n                });\n\n                if (response.ok) {\n                    alert(`${name} を追加しました！`);\n                    closeSettings();\n                    fetchPartners(); // Refresh list\n                    document.getElementById(\'newPartnerName\').value = \'\';\n                    document.getElementById(\'newPartnerLineId\').value = \'\';\n                } else {\n                    alert(\'追加に失敗しました。\');\n                }\n            } catch (error) {\n                console.error(\'Error adding partner:\', error);\n                alert(\'通信エラーが発生しました。バックエンドが起動しているか確認してください。\');\n            }\n        }\n\n\n        async function fetchPartners() {\n            try {\n                const res = await fetch(`${API_BASE}/partners`);\n                allPartners = await res.json();\n                renderSettingsPartners(allPartners);\n                renderDispatchPartnerMenu(allPartners);\n            } catch (err) {\n                console.error("Failed to load partners", err);\n            }\n        }\n\n        async function fetchInquiries() {\n            try {\n                const res = await fetch(`${API_BASE}/inquiries`);\n                const inquiries = await res.json();\n                window.lastInquiries = inquiries;\n                renderInbox(inquiries);\n                renderCompletedGroups();\n            } catch (err) {\n                console.error("Failed to load inquiries", err);\n            }\n        }\n\n        // ==========================\n        // UI Rendering Logic\n        // ==========================\n        function renderSettingsPartners(partners) {\n            const list = document.getElementById(\'partnerList\');\n            if (partners.length === 0) {\n                list.innerHTML = `<div class="text-center text-xs text-gray-400 py-2">協力会社が登録されていません</div>`;\n                return;\n            }\n            let html = \'\';\n            partners.forEach(p => {\n                const line = p.line_group_id || \'未設定\';\n                const emoji = p.icon_emoji || \'🏢\';\n                html += `\n                    <div class="bg-white p-2.5 rounded-lg border border-gray-100 shadow-sm flex justify-between items-center" id="p-item-${p.id}">\n                        <div class="flex items-center gap-3">\n                            <div class="w-8 h-8 rounded bg-blue-50 text-blue-600 flex items-center justify-center text-sm">${emoji}</div>\n                            <div>\n                                <p class="font-bold text-xs">${p.name}</p>\n                                <p class="text-[9px] text-gray-500">LINE: ${line}</p>\n                            </div>\n                        </div>\n                        <button onclick="deletePartner(${p.id})" class="text-red-400 hover:text-red-600 hover:bg-red-50 p-1.5 rounded transition">\n                            <svg class="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>\n                        </button>\n                    </div>\n                `;\n            });\n            list.innerHTML = html;\n        }\n\n        function renderDispatchPartnerMenu(partners) {\n            // Replace the hardcoded partner select menu in dispatch view\n            const container = document.querySelector(\'#screen-dispatch .flex-1.p-3.overflow-y-auto\');\n            if (!container) return; // Prevent errors if DOM missing\n            \n            // Re-inject the list \n            const headerHTML = `<p class="text-[11px] text-gray-500 mb-2 font-bold">送出先の協力会社を選択</p>`;\n            let pHTML = \'\';\n            \n            if(partners.length === 0) {\n                pHTML = `<div class="text-center text-xs text-gray-400">協力会社を登録してください</div>`;\n            } else {\n                partners.forEach(p => {\n                    const emoji = p.icon_emoji || \'🏢\';\n                    const id = `partner-disp-${p.id}`;\n                    \n                    pHTML += `\n                    <div class="bg-white border border-gray-200 rounded-lg overflow-hidden partner-card mb-3" id="card-${id}">\n                        <button onclick="togglePartner(\'${id}\')" class="w-full px-3 py-3 flex justify-between items-center bg-gray-50">\n                            <div class="flex items-center gap-2">\n                                <div class="w-8 h-8 bg-blue-100 text-blue-600 rounded-full flex items-center justify-center text-sm">${emoji}</div>\n                                <div class="text-left">\n                                    <h4 class="font-bold text-sm">${p.name}</h4>\n                                    <p class="text-[9px] text-gray-500">LINEへ連携</p>\n                                </div>\n                            </div>\n                            <svg class="w-4 h-4 text-gray-400 transition-transform" id="arrow-${id}" fill="none" stroke="currentColor" viewBox="0 0 24 24">\n                                <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M19 9l-7 7-7-7"></path>\n                            </svg>\n                        </button>\n                        <div id="form-${id}" class="accordion-content bg-white px-3 border-t">\n                            <p class="text-[10px] text-gray-500 mb-2 text-center bg-gray-50 p-1 rounded">※上の顧客データがLINEに送信されます</p>\n                            <button onclick="sendToPartner(${p.id})" id="btn-send-partner-${p.id}" class="w-full bg-blue-600 text-white font-bold py-2 rounded shadow text-xs">\n                                この会社へLINE送信\n                            </button>\n                        </div>\n                    </div>\n                    `;\n                });\n            }\n            container.innerHTML = headerHTML + pHTML;\n        }\n\n        function getWeekNumberString(d) {\n            const date = new Date(Date.UTC(d.getFullYear(), d.getMonth(), d.getDate()));\n            date.setUTCDate(date.getUTCDate() + 4 - (date.getUTCDay() || 7));\n            const yearStart = new Date(Date.UTC(date.getUTCFullYear(), 0, 1));\n            const weekNo = Math.ceil((((date - yearStart) / 86400000) + 1) / 7);\n            return `${date.getUTCFullYear()}年 第${weekNo}週`;\n        }\n\n        function toggleGroup(safeId) {\n            const isHidden = document.getElementById(`group-${safeId}`).classList.toggle(\'hidden\');\n            document.getElementById(`icon-${safeId}`).classList.toggle(\'rotate-180\');\n            if (isHidden) {\n                window.openGroups.delete(safeId);\n            } else {\n                window.openGroups.add(safeId);\n            }\n        }\n\n        async function deleteInquiryTask(id) {\n            if (!confirm(`本当に受付番号 ${id} の記録を削除しますか？\\n（この操作は取り消せません）`)) return;\n            try {\n                const res = await fetch(`${API_BASE}/inquiries/${id}`, { method: \'DELETE\' });\n                if (res.ok) {\n                    window.lastInquiries = window.lastInquiries.filter(i => i.id !== id);\n                    renderCompletedGroups();\n                } else {\n                    alert(\'削除に失敗しました。\');\n                }\n            } catch(e) {\n                console.error(e);\n                alert(\'削除中に通信エラーが発生しました。\');\n            }\n        }\n\n        async function manualCompleteInquiry(id) {\n            if (!confirm(`受付番号 ${id} を手動で「完了」にしますか？`)) return;\n            try {\n                const res = await fetch(`${API_BASE}/inquiries/${id}/complete`, { \n                    method: \'POST\',\n                    headers: { \'Content-Type\': \'application/json\' },\n                    body: JSON.stringify({ note: "管理者による手動完了" })\n                });\n                if (res.ok) {\n                    fetchInquiries(); // Refresh all\n                } else {\n                    alert(\'完了処理に失敗しました。\');\n                }\n            } catch(e) {\n                console.error(e);\n                alert(\'通信エラーが発生しました。\');\n            }\n        }\n\n        function renderCompletedGroups() {\n            const completedList = document.getElementById(\'completedList\');\n            if (!completedList) return;\n            if (!window.openGroups) window.openGroups = new Set();\n\n            const inquiries = window.lastInquiries || [];\n            const completedInquiries = inquiries.filter(req => req.status === \'completed\');\n            \n            const groupBy = document.getElementById(\'archive-grouping\') ? document.getElementById(\'archive-grouping\').value : \'month\';\n            const groups = {};\n\n            completedInquiries.forEach(req => {\n                const dateObj = new Date(req.updated_at || req.created_at || Date.now());\n                let groupKey = \'\';\n                \n                if (groupBy === \'year\') {\n                    groupKey = `${dateObj.getFullYear()}年`;\n                } else if (groupBy === \'week\') {\n                    groupKey = getWeekNumberString(dateObj);\n                } else {\n                    // Default to month\n                    groupKey = `${dateObj.getFullYear()}年${String(dateObj.getMonth() + 1).padStart(2, \'0\')}月`;\n                }\n\n                if (!groups[groupKey]) groups[groupKey] = [];\n                \n                const badge = `<span class="bg-green-100 text-green-700 text-[10px] font-bold px-2 py-0.5 rounded mr-1 flex-shrink-0">完了</span>`;\n                const cardHtml = `\n                    <div class="bg-white border border-gray-200 rounded-lg shadow-sm p-3 mb-3 relative group">\n                        <div class="flex justify-between items-start border-b pb-1 mb-2">\n                            <span class="font-bold text-sm text-gray-800 pr-2">${req.customer_name} 様 <span class="text-gray-400 text-[10px] ml-1">${req.id}</span></span>\n                            <div class="flex items-center gap-2">\n                                ${badge}\n                                <button onclick="deleteInquiryTask(\'${req.id}\')" title="この記録を削除" class="text-gray-300 hover:text-red-500 hover:bg-red-50 p-1 rounded transition opacity-50 hover:opacity-100">\n                                    <svg class="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>\n                                </button>\n                            </div>\n                        </div>\n                        <p class="text-[10px] text-gray-500 truncate mb-1">ご住所: ${req.pickup_location}</p>\n                        <p class="text-[10px] text-gray-500 truncate mb-2">お荷物番号: ${req.delivery_location}</p>\n                        <p class="text-[11px] text-gray-600 truncate mb-2 bg-gray-50 p-1 rounded">内容: ${req.detail}</p>\n                    </div>\n                `;\n                groups[groupKey].push(cardHtml);\n            });\n\n            // Sort group keys descending\n            const sortedKeys = Object.keys(groups).sort((a, b) => b.localeCompare(a));\n            \n            let html = \'\';\n            sortedKeys.forEach(key => {\n                const safeId = key.replace(/[^\\w-]/g, \'-\');\n                const isOpen = window.openGroups.has(safeId);\n                const hiddenClass = isOpen ? \'\' : \'hidden\';\n                const rotateClass = isOpen ? \'rotate-180\' : \'rotate-0\';\n\n                html += `\n                    <div class="mb-4">\n                        <button onclick="toggleGroup(\'${safeId}\')" class="w-full flex justify-between items-center bg-emerald-50 px-3 py-2 rounded shadow-sm text-sm font-bold text-emerald-800 mb-2 transition border border-emerald-100 outline-none">\n                            <span>📅 ${key} <span class="text-xs font-normal ml-1">(${groups[key].length}件)</span></span>\n                            <svg id="icon-${safeId}" class="w-4 h-4 transition-transform duration-200 transform text-emerald-600 ${rotateClass}" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M19 9l-7 7-7-7"></path></svg>\n                        </button>\n                        <div id="group-${safeId}" class="space-y-3 transition-all duration-300 ${hiddenClass}">\n                            ${groups[key].join(\'\')}\n                        </div>\n                    </div>\n                `;\n            });\n\n            completedList.innerHTML = html || `<div class="text-center py-10 text-gray-400 text-sm">完了済みの案件はありません。</div>`;\n        }\n\n        function renderInbox(inquiries) {\n            const inboxList = document.getElementById(\'inboxList\');\n            const unhandledCount = inquiries.filter(i => i.status === \'received\').length;\n            \n            document.getElementById(\'inbox-badge\')?.classList.toggle(\'hidden\', unhandledCount === 0);\n            if(unhandledCount > 0) document.getElementById(\'inbox-badge\').innerText = unhandledCount;\n            \n            let inboxHtml = \'\';\n            \n            inquiries.forEach((req, idx) => {\n                if(req.status === \'completed\') return; // Handled by renderCompletedGroups\n                \n                const isNew = idx === 0 && unhandledCount > 0 && req.status === \'received\';\n                const badge = req.status === \'dispatched\' ? `<span class="bg-yellow-100 text-yellow-700 text-[10px] font-bold px-2 py-0.5 rounded mr-1">手配中</span>` :\n                              isNew ? `<span class="bg-red-100 text-red-700 text-[10px] font-bold px-2 py-0.5 rounded mr-1 animate-pulse">新着</span>` :\n                              `<span class="bg-blue-100 text-blue-700 text-[10px] font-bold px-2 py-0.5 rounded mr-1">受付済</span>`;\n                              \n                const btnState = req.status === \'received\' ? \n                    `<button onclick="goToDispatchById(\'${req.id}\')" class="w-full bg-indigo-600 text-white py-1.5 rounded text-xs font-bold hover:bg-indigo-700 transition shadow-sm mt-2">データを確認して協力会社の手配へ</button>` :\n                    req.status === \'dispatched\' ? `\n                        <div class="flex gap-2 mt-2">\n                            <div class="flex-1 bg-gray-100 text-gray-500 py-1.5 rounded text-xs font-bold text-center border border-gray-200 flex items-center justify-center">報告待ち</div>\n                            <button onclick="manualCompleteInquiry(\'${req.id}\')" class="flex-1 bg-emerald-600 hover:bg-emerald-700 text-white py-1.5 rounded text-xs font-bold transition shadow-sm flex items-center justify-center gap-1">\n                                <svg class="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M5 13l4 4L19 7"></path></svg>\n                                手動で完了\n                            </button>\n                        </div>\n                    ` : \'\';\n\n                const cardHtml = `\n                    <div class="bg-white ${req.status===\'received\' ? \'border-l-4 border-blue-500\' : \'border border-gray-200\'} rounded-lg shadow-sm p-3 mb-3 ${isNew ? \'new-request-anim\' : \'\'}">\n                        <div class="flex justify-between border-b pb-1 mb-2">\n                            <span class="font-bold text-sm text-gray-800">${req.customer_name} 様 <span class="text-gray-400 text-[10px] ml-1">${req.id}</span></span>\n                            <div>${badge}</div>\n                        </div>\n                        <p class="text-[10px] text-gray-500 truncate mb-1">ご住所: ${req.pickup_location}</p>\n                        <p class="text-[10px] text-gray-500 truncate mb-2">お荷物番号: ${req.delivery_location}</p>\n                        <p class="text-[11px] text-gray-600 truncate mb-2 bg-gray-50 p-1 rounded">内容: ${req.detail}</p>\n                        ${btnState}\n                    </div>\n                `;\n                inboxHtml += cardHtml;\n            });\n            \n            inboxList.innerHTML = inboxHtml || `<div class="text-center py-10 text-gray-400 text-sm" id="emptyInbox">顧客からのお問い合わせを待機中...</div>`;\n            document.getElementById(\'emptyInbox\')?.classList.toggle(\'hidden\', inboxHtml.length > 0);\n        }\n\n        function updateProgress(step) {\n            for (let i = 1; i <= 4; i++) {\n                const circle = document.getElementById(`circle-${i}`);\n                const text = document.getElementById(`text-${i}`);\n                const line = document.getElementById(`line-${i}`);\n\n                if (i < step) {\n                    circle.className = "w-8 h-8 rounded-full border-2 flex items-center justify-center font-bold text-sm step-done transition-colors duration-300";\n                    circle.innerHTML = "✓";\n                    text.className = "ml-2 text-sm font-bold text-emerald-600";\n                    if (line) line.classList.replace(\'bg-gray-200\', \'bg-emerald-500\');\n                } else if (i === step) {\n                    circle.className = "w-8 h-8 rounded-full border-2 flex items-center justify-center font-bold text-sm step-active transition-colors duration-300";\n                    circle.innerHTML = i;\n                    text.className = "ml-2 text-sm font-bold text-blue-600";\n                    if (line) line.classList.replace(\'bg-emerald-500\', \'bg-gray-200\');\n                } else {\n                    circle.className = "w-8 h-8 rounded-full border-2 flex items-center justify-center font-bold text-sm step-inactive transition-colors duration-300";\n                    circle.innerHTML = i;\n                    text.className = "ml-2 text-sm font-bold text-gray-400";\n                    if (line) line.classList.replace(\'bg-emerald-500\', \'bg-gray-200\');\n                }\n            }\n\n            if (step === 2) {\n                document.getElementById(\'badge-step-2\').classList.replace(\'opacity-50\', \'text-yellow-300\');\n                document.getElementById(\'badge-step-3\').classList.replace(\'text-yellow-300\', \'opacity-50\');\n            } else if (step === 3) {\n                document.getElementById(\'badge-step-2\').classList.replace(\'text-yellow-300\', \'opacity-50\');\n                document.getElementById(\'badge-step-3\').classList.replace(\'opacity-50\', \'text-yellow-300\');\n            } else if (step === 4) {\n                const arrow = document.getElementById(\'arrow-to-partner\');\n                if (arrow) arrow.classList.replace(\'text-gray-300\', \'text-blue-500\');\n                const pZone = document.getElementById(\'partner-zone\');\n                if (pZone) pZone.classList.remove(\'opacity-50\', \'pointer-events-none\');\n                const b4 = document.getElementById(\'badge-step-4\');\n                if (b4) b4.classList.replace(\'bg-gray-400\', \'bg-[#06C755]\');\n            }\n        }\n\n        function switchTab(tabName) {\n            const tabs = [\'inbox\', \'dispatch\', \'completed\'];\n            tabs.forEach(t => {\n                const btn = document.getElementById(`tab-${t}`);\n                const screen = document.getElementById(`screen-${t}`);\n\n                if (t === tabName) {\n                    btn.classList.replace(\'text-gray-400\', \'text-blue-600\');\n                    btn.classList.replace(\'border-transparent\', \'border-blue-600\');\n                    btn.classList.add(\'bg-blue-50\');\n                    screen.classList.remove(\'screen-hidden\');\n                    setTimeout(() => screen.classList.remove(\'opacity-0\'), 20);\n                } else {\n                    btn.classList.replace(\'text-blue-600\', \'text-gray-400\');\n                    btn.classList.replace(\'border-blue-600\', \'border-transparent\');\n                    btn.classList.remove(\'bg-blue-50\');\n                    screen.classList.add(\'opacity-0\');\n                    setTimeout(() => {\n                        if (btn.classList.contains(\'text-gray-400\')) screen.classList.add(\'screen-hidden\');\n                    }, 400); \n                }\n            });\n            if (tabName === \'inbox\') document.getElementById(\'inbox-badge\')?.classList.add(\'hidden\');\n        }\n\n        // ==========================\n        // LIFF Form\n        // ==========================\n        function openLiff() {\n            document.getElementById(\'liffModal\').classList.add(\'open\');\n        }\n        function closeLiff() {\n            document.getElementById(\'liffModal\').classList.remove(\'open\');\n        }\n\n        async function submitLiff(event) {\n            event.preventDefault();\n            const btn = document.getElementById(\'btn-submit-liff\');\n            btn.innerText = "送信中...";\n            btn.disabled = true;\n\n            const payload = {\n                customer_name: document.getElementById(\'df-name\').value,\n                phone_number: document.getElementById(\'df-phone\').value,\n                pickup_location: document.getElementById(\'df-from\').value,\n                delivery_location: document.getElementById(\'df-to\').value,\n                detail: document.getElementById(\'df-detail\').value\n            };\n\n            try {\n                const res = await fetch(`${API_BASE}/inquiries`, {\n                    method: \'POST\',\n                    headers: { \'Content-Type\': \'application/json\' },\n                    body: JSON.stringify(payload)\n                });\n                if (!res.ok) throw new Error("LIFF submission failed");\n                const inquiry = await res.json();\n\n                closeLiff();\n                btn.innerText = "問い合わせを送信";\n                btn.disabled = false;\n\n                const chat = document.getElementById(\'customerChat\');\n                chat.insertAdjacentHTML(\'beforeend\', `\n                    <div class="flex mb-4 mt-2">\n                        <div class="w-8 h-8 rounded-full bg-blue-600 flex items-center justify-center text-white font-bold mr-2 text-xs shrink-0">要</div>\n                        <div class="chat-bubble left bg-white rounded-xl rounded-tl-sm shadow-md p-3 text-xs">\n                            お問い合わせありがとうございます。確認次第手配を進めます！<br>\n                            <span class="text-gray-400 text-[10px]">受付番号: ${inquiry.id}</span>\n                        </div>\n                    </div>\n                `);\n                chat.scrollTop = chat.scrollHeight;\n\n                updateProgress(2);\n                await fetchInquiries();\n\n            } catch (err) {\n                console.error(err);\n                alert("送信に失敗しました");\n                btn.innerText = "問い合わせを送信";\n                btn.disabled = false;\n            }\n        }\n\n        // ==========================\n        // Dispatch Flow\n        // ==========================\n        function goToDispatchById(id) {\n            const inquiry = window.lastInquiries.find(i => String(i.id) === String(id));\n            if (inquiry) {\n                goToDispatch(inquiry);\n            } else {\n                alert("指定されたデータが見つかりません。画面を更新してください。");\n            }\n        }\n\n        function goToDispatch(inquiry) {\n            updateProgress(3);\n            currentData = inquiry;\n\n            document.getElementById(\'pass-name\').innerText = inquiry.customer_name;\n            document.getElementById(\'pass-phone\').innerText = inquiry.phone_number;\n            document.getElementById(\'pass-detail\').innerText = `ご住所: ${inquiry.pickup_location}\\nお荷物番号: ${inquiry.delivery_location}\\n詳細: ${inquiry.detail}`;\n\n            switchTab(\'dispatch\');\n            document.getElementById(\'dispatch-empty\').classList.add(\'hidden\');\n            document.getElementById(\'dispatch-content\').classList.remove(\'hidden\');\n            \n            // Re-render partners menu to ensure reset state\n            renderDispatchPartnerMenu(allPartners);\n            \n            document.getElementById(\'dashStatus\').innerHTML = `\n                <div class="flex items-center gap-2">\n                    <span class="w-2 h-2 rounded-full bg-gray-300" id="statusDot"></span>\n                    <span>ステータス: <span class="font-bold" id="statusText">待機中</span></span>\n                </div>\n            `;\n        }\n\n        let currentActivePartnerId = null;\n        function togglePartner(id) {\n            if (currentActivePartnerId && currentActivePartnerId !== id) {\n                const oldContent = document.getElementById(`form-${currentActivePartnerId}`);\n                if (oldContent) {\n                    oldContent.classList.remove(\'open\');\n                    document.getElementById(`arrow-${currentActivePartnerId}`).classList.remove(\'rotate-180\');\n                    document.getElementById(`card-${currentActivePartnerId}`).classList.remove(\'active\');\n                }\n            }\n            document.getElementById(`form-${id}`).classList.toggle(\'open\');\n            document.getElementById(`arrow-${id}`).classList.toggle(\'rotate-180\');\n            document.getElementById(`card-${id}`).classList.toggle(\'active\');\n            currentActivePartnerId = document.getElementById(`form-${id}`).classList.contains(\'open\') ? id : null;\n        }\n\n        async function sendToPartner(partnerId) {\n            if (!currentData) return;\n            \n            const btn = document.getElementById(`btn-send-partner-${partnerId}`);\n            btn.innerHTML = \'送信中...\';\n            btn.disabled = true;\n\n            try {\n                const res = await fetch(`${API_BASE}/inquiries/${currentData.id}/dispatch`, {\n                    method: \'POST\',\n                    headers: { \'Content-Type\': \'application/json\' },\n                    body: JSON.stringify({ partner_id: partnerId })\n                });\n                if (!res.ok) throw new Error("Dispatch failed");\n\n                btn.innerHTML = \'✔ 送信完了\';\n                btn.classList.replace(\'bg-blue-600\', \'bg-gray-400\');\n\n                document.getElementById(\'statusText\').innerText = "協力会社へ連絡依頼済み（完了報告待ち）";\n                document.getElementById(\'statusText\').classList.add(\'text-blue-600\');\n                document.getElementById(\'statusDot\').classList.replace(\'bg-gray-300\', \'bg-blue-500\');\n                document.getElementById(\'statusDot\').classList.add(\'animate-pulse\');\n\n                updateProgress(4);\n                fetchInquiries(); // Background update inbox\n\n                document.getElementById(\'partnerEmpty\').classList.add(\'hidden\');\n                \n                // Show message on Partner side\n                const chat = document.getElementById(\'partnerChat\');\n                const msgHTML = `\n                    <div class="flex mb-4 mt-2 opacity-0 translate-y-4 transition-all duration-300" id="incoming-${currentData.id}">\n                        <div class="w-8 h-8 rounded-full bg-blue-600 flex items-center justify-center text-white font-bold mr-2 text-xs shrink-0 shadow-md">要</div>\n                        <div class="chat-bubble left bg-white rounded-xl rounded-tl-sm shadow-md p-3 text-sm w-full">\n                            <div class="bg-blue-600 text-white px-2 py-1 text-[10px] font-bold mb-2 rounded flex-wrap gap-1">\n                                📞 お客様への連絡依頼\n                            </div>\n                            <p class="text-[11px] font-bold mb-1">${currentData.customer_name}</p>\n                            <p class="text-blue-600 text-[11px] font-bold mb-2">☎️ ${currentData.phone_number}</p>\n                            <div class="text-[10px] text-gray-600 bg-gray-50 p-1.5 rounded mb-3 border border-gray-100">\n                                引取: ${currentData.pickup_location}<br>\n                                納品: ${currentData.delivery_location}<br>\n                                ${currentData.detail}\n                            </div>\n                            <button onclick="reportDone(this, \'${currentData.id}\', \'partner-disp-${partnerId}\')" class="w-full bg-[#06C755] hover:bg-green-600 text-white font-bold py-2 rounded shadow text-xs transition">\n                                連絡完了として報告\n                            </button>\n                        </div>\n                    </div>\n                `;\n                chat.insertAdjacentHTML(\'beforeend\', msgHTML);\n                chat.scrollTop = chat.scrollHeight;\n\n                setTimeout(() => {\n                    const el = document.getElementById(`incoming-${currentData.id}`);\n                    if (el) el.classList.remove(\'opacity-0\', \'translate-y-4\');\n                }, 50);\n\n            } catch (err) {\n                console.error(err);\n                alert("手配依頼の送信に失敗しました");\n                btn.innerHTML = \'この会社へLINE送信\';\n                btn.disabled = false;\n            }\n        }\n\n        async function reportDone(btn, inquiryId, cardId) {\n            btn.innerHTML = "報告中...";\n            btn.disabled = true;\n\n            try {\n                const res = await fetch(`${API_BASE}/inquiries/${inquiryId}/complete`, { method: \'POST\' });\n                if (!res.ok) throw new Error("Complete failed");\n\n                btn.innerHTML = "✔ 報告済み";\n                btn.className = "w-full bg-gray-200 text-gray-500 font-bold py-2 rounded shadow-inner text-xs cursor-not-allowed";\n\n                const chat = document.getElementById(\'partnerChat\');\n                chat.insertAdjacentHTML(\'beforeend\', `\n                    <div class="flex flex-row-reverse mb-3 mt-1 opacity-0 translate-y-4 transition-all duration-300" id="done-${Date.now()}">\n                        <div class="chat-bubble right bg-[#06C755] text-white rounded-xl rounded-tr-sm p-2 shadow-sm text-xs max-w-[80%]">\n                            お客様への連絡、完了しました！\n                        </div>\n                    </div>\n                `);\n                chat.scrollTop = chat.scrollHeight;\n\n                setTimeout(() => {\n                    chat.lastElementChild.classList.remove(\'opacity-0\', \'translate-y-4\');\n                }, 50);\n\n                // Update Dash\n                document.getElementById(\'statusText\').innerText = "✅ 連絡完了の報告を受け取りました";\n                document.getElementById(\'statusText\').classList.replace(\'text-blue-600\', \'text-green-600\');\n                document.getElementById(\'statusDot\').classList.replace(\'bg-blue-500\', \'bg-green-500\');\n                document.getElementById(\'statusDot\').classList.remove(\'animate-pulse\');\n                document.getElementById(`card-${cardId}`)?.classList.add(\'border-green-400\', \'bg-green-50\');\n\n                for (let i = 1; i <= 4; i++) {\n                    const circle = document.getElementById(`circle-${i}`);\n                    const text = document.getElementById(`text-${i}`);\n                    circle.className = "w-8 h-8 rounded-full border-2 flex items-center justify-center font-bold text-sm step-done transition-colors duration-300";\n                    circle.innerHTML = "✓";\n                    text.className = "ml-2 text-sm font-bold text-emerald-600";\n                }\n                \n                fetchInquiries(); // Refetch to mark inbox item as completed if they go back\n\n            } catch (err) {\n                console.error(err);\n                alert("完了報告に失敗しました");\n                btn.innerHTML = \'連絡完了として報告\';\n                btn.disabled = false;\n            }\n        }\n\n        // ==========================\n        // Settings / Custom Partner\n        // ==========================\n        function openSettings() {\n            document.getElementById(\'settingsPanel\').classList.remove(\'translate-y-full\');\n        }\n        function closeSettings() {\n            document.getElementById(\'settingsPanel\').classList.add(\'translate-y-full\');\n            document.getElementById(\'addAlert\').classList.add(\'hidden\');\n        }\n\n        async function addPartner() {\n            const nameInput = document.getElementById(\'newPartnerName\');\n            const lineInput = document.getElementById(\'newPartnerLine\');\n            const name = nameInput.value.trim();\n            const line = lineInput.value.trim();\n            const alertEl = document.getElementById(\'addAlert\');\n\n            if (!name) {\n                alertEl.classList.remove(\'hidden\');\n                return;\n            }\n            alertEl.classList.add(\'hidden\');\n            \n            const btn = event.target;\n            btn.innerHTML = \'追加中...\';\n            btn.disabled = true;\n\n            try {\n                const res = await fetch(`${API_BASE}/partners`, {\n                    method: \'POST\',\n                    headers: { \'Content-Type\': \'application/json\' },\n                    body: JSON.stringify({ name: name, line_group_id: line, icon_emoji: \'🆕\' })\n                });\n                if (!res.ok) throw new Error("Add partner failed");\n                nameInput.value = \'\';\n                lineInput.value = \'\';\n                await fetchPartners();\n            } catch (err) {\n                console.error(err);\n                alert("協力会社の追加に失敗しました。");\n            } finally {\n                btn.innerHTML = \'＋ 追加する\';\n                btn.disabled = false;\n            }\n        }\n\n        async function deletePartner(id) {\n            if (confirm(\'この協力会社を削除しますか？\')) {\n                const el = document.getElementById(`p-item-${id}`);\n                if (el) {\n                    el.classList.add(\'opacity-0\', \'scale-95\', \'transition-all\', \'duration-300\');\n                    setTimeout(() => el.remove(), 300);\n                }\n                try {\n                    await fetch(`${API_BASE}/partners/${id}`, { method: \'DELETE\' });\n                    // Refresh data behind the scenes\n                    const res = await fetch(`${API_BASE}/partners`);\n                    allPartners = await res.json();\n                    renderDispatchPartnerMenu(allPartners);\n                } catch (err) {\n                    console.error("Delete failed", err);\n                }\n            }\n        }\n    </script>\n\n<script>\n    // Clean up unnecessary JS references to mock phones that no longer exist\n    // Just override the error-prone functions or references if needed\n    const _originalUpdatePartnerPhone = window.updatePartnerPhone;\n    if(typeof updatePartnerPhone !== \'undefined\') {\n        window.updatePartnerPhone = function() { }; // disable partner mock update\n    }\n    \n    // Auto-fetch every 3 seconds\n    setInterval(fetchInquiries, 3000);\n</script>\n</body>\n</html>\n'